const table = Array.from({ length: 16 }, (_, i) => i);
export default function Blocks({
  nums,
  chosenExtraNums,
  blockNums,
  isWin,
  seconds,
  handleClickNum,
  handleClickChosenExtraNum,
}) {
  return (
    <div>
      {table.map((t, i) =>
        blockNums.includes(t) ? (
          <button
            style={{
              border: "1px solid black",
              borderRadius: "12px",
              padding: "5px",
              width: "40px",
              display: "inline",
              position: "relative",
              top: "20px",
              background: chosenExtraNums[t]?.clicked && "gray",
              margin: "5px",
            }}
            onClick={handleClickChosenExtraNum}
            disabled={isWin !== "" || seconds < 1}
            key={i}
          >
            {chosenExtraNums[t]?.number}
          </button>
        ) : (
          <button
            style={{
              border: "1px solid black",
              borderRadius: "12px",
              padding: "5px",
              width: "40px",
              display: "inline",
              position: "relative",
              top: "20px",
              background:
                nums.find((obj) => obj.blockNum === t)?.clicked &&
                (isWin === "" || isWin === true)
                  ? "gray"
                  : isWin === false && "lightblue",
              // color: "red",
              margin: "5px",
            }}
            onClick={handleClickNum}
            disabled={isWin !== "" || seconds < 1}
            key={i}
          >
            {nums.find((obj) => obj.blockNum === t)?.number}
          </button>
        ),
      )}
    </div>
  );
}
