import { useState, useEffect } from "react";
import ConfirmationBox from "../ConfirmationBox";
import GameLevel from "../GameLevel";
import Rock from "./Rock.png";
import Scissors from "./Scissors.png";
import Paper from "./Paper.png";
import { getRandNum } from "../utils";
import { useNavigate } from "react-router-dom";
import ReviewSection from "../../Components/ReviewSection";
import AboutRockScissorsPaper from "./AboutRockScissorsPaper";
const optionsArray = ["Rock", "Scissors", "Paper"];

export default function RockScissorsPaper({ updateTotalPoint, currentUser }) {
  const [isAboutPage, setIsAboutPage] = useState(false);
  const [isGameStarted, setIsGameStarted] = useState(false);
  const [userChoice, setUserChoice] = useState("");
  const [pejmanChoice, setPejmanChoice] = useState("");
  const [gameResult, setGameResult] = useState("");
  const [score, setScore] = useState(0);
  const [tripleScore, setTripleScore] = useState(0);
  const [showImages, setShowImages] = useState(true);
  const [isTogglingReset, setIsTogglingReset] = useState(false);
  const [isTogglingHomePage, setIsTogglingHomePage] = useState(false);
  const [normalMode, setNormalMode] = useState(false);
  const [extremelySuperDifficultMode, setExtremelySuperDifficultMode] =
    useState(false);
  const [isTogglingLevel, setIsTogglingLevel] = useState(false);
  const [showReviews, setShowReviews] = useState(true);

  const navigate = useNavigate();
  const runNormalMode = () => {
    setNormalMode(true);
    setExtremelySuperDifficultMode(false);
  };
  const runExtremelySuperDifficultMode = () => {
    setExtremelySuperDifficultMode(true);
    setNormalMode(false);
  };
  const handleStart = () => {
    setIsGameStarted(true);
  };
  const announcingTheWinner = (user, pejman) => {
    if (user === "" || pejman === "") return;
    else if (user === pejman) {
      setGameResult("No winner!");
    } else if (user === "Rock" && pejman === "Scissors") {
      setGameResult("You win!");
      updateScore(1);
      setTripleScore((currTripleScore) => currTripleScore + 1);
    } else if (user === "Scissors" && pejman === "Paper") {
      setGameResult("You win!");
      updateScore(1);
      setTripleScore((currTripleScore) => currTripleScore + 1);
    } else if (user === "Paper" && pejman === "Rock") {
      setGameResult("You win!");
      updateScore(1);
      setTripleScore((currTripleScore) => currTripleScore + 1);
    } else {
      setGameResult("Pejman wins!");
      updateScore(-1);
      setTripleScore(0);
    }
  };
  const updateScore = (i) => {
    setScore((currScore) => currScore + i);
  };
  const handleUserChoice = (input) => {
    setUserChoice(input);
    if (normalMode) {
      setPejmanChoice(optionsArray[getRandNum(3) - 1]);
    } else if (extremelySuperDifficultMode) {
      if (input === "Rock") {
        setPejmanChoice("Paper");
      } else if (input === "Paper") {
        setPejmanChoice("Scissors");
      } else if (input === "Scissors") {
        setPejmanChoice("Rock");
      }
    }
    setShowImages(false);
  };
  const handleTotalPoint = () => {
    if (tripleScore === 3) {
      setTripleScore(0);
    }
  };
  const handleOk = () => {
    updateTotalPoint(1);
    setTripleScore(0);
    setUserChoice("");
    setPejmanChoice("");
    setGameResult("");
  };
  const toggleHomePage = () => {
    setIsTogglingHomePage(true);
  };
  const toggleHomePageYes = () => {
    navigate("/");
  };
  const toggleHomePageCancel = () => {
    setIsTogglingHomePage(false);
  };
  const toggleReset = () => {
    setIsTogglingReset(true);
  };
  const toggleResetYes = () => {
    setScore(0);
    setTripleScore(0);
    setUserChoice("");
    setPejmanChoice("");
    setGameResult("");
    setIsTogglingReset(false);
    setShowReviews(true);
  };
  const toggleResetCancel = () => {
    setIsTogglingReset(false);
  };
  const togglePlayAgainYes = () => {
    setUserChoice("");
    setPejmanChoice("");
    setGameResult("");
    setShowImages(true);
  };
  const togglePlayAgainCancel = () => {
    setIsTogglingHomePage(true);
  };
  const toggleLevel = () => {
    setIsTogglingLevel(true);
  };
  const toggleLevelYes = () => {
    setUserChoice("");
    setPejmanChoice("");
    setScore(0);
    setTripleScore(0);
    setGameResult("");
    if (normalMode) {
      setNormalMode(false);
      setExtremelySuperDifficultMode(true);
    } else if (extremelySuperDifficultMode) {
      setExtremelySuperDifficultMode(false);
      setNormalMode(true);
    }
    setIsTogglingLevel(false);
    setShowReviews(true);
  };
  const toggleLevelCancel = () => {
    setIsTogglingLevel(false);
  };
  const handleAboutPage = () => {
    setIsAboutPage(true);
  };
  const handleReviewSection = () => {
    setShowReviews((currShowReviews) => !currShowReviews);
  };
  useEffect(
    function () {
      handleTotalPoint();
      announcingTheWinner(userChoice, pejmanChoice);
    },
    [userChoice, pejmanChoice],
  );
  useEffect(() => {
    document.title = "Rock-Scissors-Paper";
  }, []);
  return (
    <div>
      {isAboutPage && (
        <AboutRockScissorsPaper setIsAboutPage={setIsAboutPage} />
      )}
      {!isAboutPage && (
        <div>
          <h2 className="fasterOne" style={{ fontSize: "45px" }}>
            Rock - Scissors - Paper
          </h2>
          <div className="four-buttons-container">
            {!isTogglingHomePage && !isTogglingLevel && !isTogglingReset && (
              <button className="btn3" onClick={handleAboutPage}>
                About Rock - Scissors - Paper
              </button>
            )}
            {isGameStarted &&
              !isTogglingLevel &&
              (normalMode || extremelySuperDifficultMode) &&
              !isTogglingHomePage &&
              showImages &&
              !isTogglingReset && (
                <button
                  className="btn3"
                  onClick={() => toggleLevel()}
                >{`Switch to ${
                  extremelySuperDifficultMode
                    ? "Normal Mode"
                    : "extremely-Super-Difficult Mode"
                }`}</button>
              )}
            {isGameStarted &&
              !isTogglingHomePage &&
              !isTogglingReset &&
              showImages &&
              (normalMode || extremelySuperDifficultMode) &&
              !isTogglingLevel &&
              score !== 0 && (
                <button className="btn3" onClick={() => toggleReset()}>
                  Reset the Game
                </button>
              )}
            {!isTogglingHomePage &&
              !isTogglingReset &&
              showImages &&
              !isTogglingLevel && (
                <button className="btn3" onClick={() => toggleHomePage()}>
                  Back to home page
                </button>
              )}
          </div>
          {isTogglingLevel && (
            <ConfirmationBox
              question={`Are you sure you want to switch to ${
                extremelySuperDifficultMode
                  ? "Normal Mode"
                  : "extremely-Super-Difficult Mode"
              }?`}
              toggleYes={toggleLevelYes}
              toggleCancel={toggleLevelCancel}
            />
          )}
          {isTogglingReset && (
            <ConfirmationBox
              question="Are you sure you want to reset the game? By reseting the game, your score will be reset to zero!"
              toggleYes={toggleResetYes}
              toggleCancel={toggleResetCancel}
            />
          )}
          {isTogglingHomePage && (
            <ConfirmationBox
              question="Are you sure you want to go back to Home Page?"
              toggleYes={toggleHomePageYes}
              toggleCancel={toggleHomePageCancel}
            />
          )}
          {!normalMode &&
            !extremelySuperDifficultMode &&
            !isGameStarted &&
            !isTogglingHomePage && (
              <GameLevel
                mode1="Normal"
                mode1Function={runNormalMode}
                mode2="Extremely Super Difficult"
                mode2Function={runExtremelySuperDifficultMode}
              />
            )}
          {!isGameStarted &&
            (normalMode || extremelySuperDifficultMode) &&
            !isTogglingHomePage && (
              <button
                className="btn1"
                onClick={handleStart}
                style={{ marginTop: "10px" }}
              >
                Start
              </button>
            )}
          {isGameStarted &&
            !isTogglingHomePage &&
            !isTogglingReset &&
            !isTogglingLevel &&
            showImages &&
            (normalMode || extremelySuperDifficultMode) && (
              <div>
                <img
                  src={Rock}
                  width="150px"
                  alt="Rock"
                  onClick={() => handleUserChoice("Rock")}
                  style={{ margin: "15px" }}
                />
                <img
                  src={Scissors}
                  width="150px"
                  alt="Scissors"
                  onClick={() => handleUserChoice("Scissors")}
                  style={{ margin: "15px" }}
                />
                <img
                  src={Paper}
                  width="150px"
                  alt="Paper"
                  onClick={() => handleUserChoice("Paper")}
                  style={{ margin: "15px" }}
                />
              </div>
            )}
          {!isTogglingHomePage &&
            !isTogglingReset &&
            !isTogglingLevel &&
            (normalMode || extremelySuperDifficultMode) &&
            new Array(tripleScore).fill(null).map((s, i) => (
              <div style={{ display: "inline", fontSize: "70px" }} key={i}>
                ❁
              </div>
            ))}
          {isGameStarted &&
          tripleScore === 3 &&
          !isTogglingHomePage &&
          !isTogglingReset &&
          !isTogglingLevel &&
          (normalMode || extremelySuperDifficultMode) ? (
            <div>
              <h3 className="fasterOne" style={{ fontSize: "40px" }}>
                Excellent! You just beat Pejman three times in a row
              </h3>
              <h3>Your total point increases by one</h3>
              <button className="btn2" onClick={() => handleOk()}>
                OK
              </button>
            </div>
          ) : (
            isGameStarted &&
            !isTogglingHomePage &&
            !isTogglingReset &&
            !isTogglingLevel &&
            (normalMode || extremelySuperDifficultMode) && (
              <div>
                <div>
                  {userChoice && (
                    <div>
                      Your choice: <strong>{userChoice}</strong>
                    </div>
                  )}
                </div>
                <div>
                  {pejmanChoice && (
                    <div>
                      Pejman's choice: <strong>{pejmanChoice}</strong>
                    </div>
                  )}
                </div>
                <h2>{gameResult}</h2>
                <h2>Your score: {score}</h2>
              </div>
            )
          )}
          {isGameStarted &&
            !showImages &&
            !isTogglingHomePage &&
            tripleScore !== 3 &&
            (normalMode || extremelySuperDifficultMode) && (
              <ConfirmationBox
                question="Play again?"
                toggleYes={togglePlayAgainYes}
                toggleCancel={togglePlayAgainCancel}
              />
            )}
          {!isTogglingReset &&
            !isTogglingHomePage &&
            !isTogglingLevel &&
            isGameStarted && (
              <button
                className="btn1"
                onClick={handleReviewSection}
                style={{ marginTop: "25px" }}
              >
                {showReviews
                  ? "Hide the Reviews Section"
                  : "Show the Reviews Section"}
              </button>
            )}
          {!isTogglingReset &&
            !isTogglingHomePage &&
            !isTogglingLevel &&
            isGameStarted &&
            showReviews && (
              <ReviewSection
                game="RockScissorsPaper"
                currentUser={currentUser}
              />
            )}
        </div>
      )}
    </div>
  );
}
