import E00 from "./images/000.jpg";

export default function Emoji({
  imgId,
  imgSrc,
  emojis,
  setEmojis,
  selectedEmojis,
  setSelectedEmojis,
  tripleMatch,
  isWin,
  isSelected,
  pair1ChoseEmoji,
  pair2ChoseEmoji,
}) {
  const handleClickEmoji = () => {
    setEmojis((currEmojis) =>
      currEmojis.map((emoji) =>
        emoji.id === imgId ? { ...emoji, image: E00, isSelected: true } : emoji,
      ),
    );
    for (const selectedEmoji of selectedEmojis) {
      if (selectedEmoji.isFilled === false) {
        setSelectedEmojis((currSelectedEmojis) =>
          currSelectedEmojis.map((emoji) =>
            emoji.id === selectedEmoji.id
              ? {
                  ...emoji,
                  image: emojis.find((currEmoji) => currEmoji.id === imgId)
                    .image,
                  isFilled: true,
                }
              : emoji,
          ),
        );
        break;
      }
    }
  };
  return (
    <div>
      <img
        src={imgSrc}
        style={{
          width: "35px",
          border:
            pair1ChoseEmoji && imgSrc === pair1ChoseEmoji.image
              ? "5px solid black"
              : pair2ChoseEmoji && imgSrc === pair2ChoseEmoji.image
                ? "5px dashed black"
                : "1px solid black",
          boxSizing: "border-box",
          margin: "3px",
          pointerEvents:
            imgSrc === E00 || tripleMatch || isWin !== "" || isSelected
              ? "none"
              : "",
          opacity: tripleMatch || isWin !== "" ? 0.5 : 1,
        }}
        onClick={handleClickEmoji}
        alt=""
      />
    </div>
  );
}
