import { useState, useEffect } from "react";
import Card from "./Card";
import { getRandArr } from "../utils";

export default function Board({
  images,
  board,
  setBoard,
  nrows,
  ncols,
  isImagesGroupChosen,
  easyMode,
  normalMode,
  hardMode,
  showBoard,
  visibleCards,
  setVisibleCards,
  setShowBoard,
  setIsWin,
  seconds,
  setSeconds,
  handleStartTimer,
  handleStopTimer,
  pair,
  setPair,
  isTogglingHomePage,
  isTogglingReset,
  updateTotalPoint,
  seeAllCardsChanceTemp,
  seeAllCardsChancePer,
}) {
  const [shuffledIndexes, setShuffledIndexes] = useState([]);
  const generateBoard = () => {
    let finalIndex = 0;
    for (let b = 0; b < nrows; b++) {
      let row = [];
      for (let a = 0; a < ncols; a++) {
        row.push([a, b, shuffledIndexes[finalIndex], 0]);
        finalIndex++;
      }
      setBoard((currBoard) => [...currBoard, row]);
    }
    if (normalMode) {
      setSeconds(180); // 180
      handleStartTimer();
    }
    if (hardMode) {
      setSeconds(270); // 270
      handleStartTimer();
    }
    setShowBoard(true);
  };
  useEffect(
    function () {
      function pickIndexes() {
        let copyImageIndexes = images.map((item) => item.imageIndex);
        let copyShuffledIndexes = [...shuffledIndexes];
        for (let i = 0; i < images.length; i++) {
          const randomIndex = getRandArr(copyImageIndexes);
          const randomElement = copyImageIndexes.splice(
            copyImageIndexes.indexOf(randomIndex),
            1,
          )[0];
          copyShuffledIndexes.push(randomElement);
        }
        setShuffledIndexes(copyShuffledIndexes);
      }
      pickIndexes();
    },
    [images],
  );
  return (
    <div>
      {board.map((row, i) =>
        row.map((card, j) =>
          card[0] !== ncols - 1 ? (
            <div style={{ display: "inline" }} key={`${i}-${j}`}>
              {
                <Card
                  visibleCards={visibleCards}
                  setVisibleCards={setVisibleCards}
                  x={card[0]}
                  y={card[1]}
                  images={images.map((item) => item.image)}
                  imageIndex={card[2]}
                  status={card[3]}
                  board={board}
                  setBoard={setBoard}
                  setIsWin={setIsWin}
                  seconds={seconds}
                  easyMode={easyMode}
                  normalMode={normalMode}
                  hardMode={hardMode}
                  nrows={nrows}
                  ncols={ncols}
                  pair={pair}
                  setPair={setPair}
                  handleStopTimer={handleStopTimer}
                  isTogglingReset={isTogglingReset}
                  isTogglingHomePage={isTogglingHomePage}
                  updateTotalPoint={updateTotalPoint}
                  seeAllCardsChanceTemp={seeAllCardsChanceTemp}
                  seeAllCardsChancePer={seeAllCardsChancePer}
                />
              }
            </div>
          ) : (
            <div style={{ display: "inline" }} key={`${i}-${j}`}>
              {
                <Card
                  visibleCards={visibleCards}
                  setVisibleCards={setVisibleCards}
                  x={card[0]}
                  y={card[1]}
                  images={images.map((item) => item.image)}
                  imageIndex={card[2]}
                  status={card[3]}
                  board={board}
                  setBoard={setBoard}
                  setIsWin={setIsWin}
                  seconds={seconds}
                  easyMode={easyMode}
                  normalMode={normalMode}
                  hardMode={hardMode}
                  nrows={nrows}
                  ncols={ncols}
                  pair={pair}
                  setPair={setPair}
                  handleStopTimer={handleStopTimer}
                  isTogglingReset={isTogglingReset}
                  isTogglingHomePage={isTogglingHomePage}
                  updateTotalPoint={updateTotalPoint}
                  seeAllCardsChanceTemp={seeAllCardsChanceTemp}
                  seeAllCardsChancePer={seeAllCardsChancePer}
                />
              }
              <br></br>
            </div>
          ),
        ),
      )}
      {isImagesGroupChosen && !showBoard && !isTogglingHomePage && (
        <button className="btn1" onClick={generateBoard}>
          Start
        </button>
      )}
    </div>
  );
}
